class Solution:
    def totalStrength(self, strength):
        MOD = 10**9 + 7
        n = len(strength)
        total = 0
        for i in range(n):
            running = 0
            mn = strength[i]
            for j in range(i, n):
                running += strength[j]
                if strength[j] < mn:
                    mn = strength[j]
                total += mn * running
        return total % MOD

