var totalStrength = function(strength) {
    const MOD = 1000000007n;
    const n = strength.length;
    const s = strength.map(BigInt);
    const P = new Array(n + 1).fill(0n);
    for (let i = 0; i < n; i++) P[i + 1] = P[i] + s[i];
    const PP = new Array(n + 2).fill(0n);
    for (let i = 0; i <= n; i++) PP[i + 1] = PP[i] + P[i];
    const left = new Array(n).fill(0);
    let stack = [];
    for (let i = 0; i < n; i++) {
        while (stack.length && strength[stack[stack.length - 1]] >= strength[i]) stack.pop();
        left[i] = stack.length ? stack[stack.length - 1] + 1 : 0;
        stack.push(i);
    }
    const right = new Array(n).fill(0);
    stack = [];
    for (let i = n - 1; i >= 0; i--) {
        while (stack.length && strength[stack[stack.length - 1]] > strength[i]) stack.pop();
        right[i] = stack.length ? stack[stack.length - 1] - 1 : n - 1;
        stack.push(i);
    }
    let ans = 0n;
    for (let i = 0; i < n; i++) {
        const l = BigInt(left[i]);
        const r = BigInt(right[i]);
        const bi = BigInt(i);
        const pos = ((bi - l + 1n) * (((PP[right[i] + 2] - PP[i + 1]) % MOD + MOD) % MOD)) % MOD;
        const neg = ((r - bi + 1n) * (((PP[i + 1] - PP[l] % MOD) % MOD + MOD) % MOD)) % MOD;
        ans = (ans + s[i] * (((pos - neg) % MOD + MOD) % MOD)) % MOD;
        ans = ((ans % MOD) + MOD) % MOD;
    }
    return Number(((ans % MOD) + MOD) % MOD);
};
